+    // Actual measurement (weights should be cached)
+    var total_time: i64 = 0;
+    const n_iterations = 5;
+    var last_result: ?[]f32 = null;
+
+    for (0..n_iterations) |i| {
+        const start = std.time.milliTimestamp();
+        const result = try engine.moeFFN_Q4(
+            allocator,
+            single_input,
+            router_weights,
+            expert_gate,
+            expert_up,
+            expert_down,
+            n_expert,
+            n_embd,
+            n_ff,
